 -- BASIC LEVEL
-- Total number of customers
SELECT COUNT(*) AS total_customers
FROM FOOD_CUSTOMERS;

-- Total number of orders
SELECT COUNT(*) AS total_orders
FROM FOOD_ORDERS;

-- Total revenue generated
SELECT SUM(ORDER_AMOUNT) AS total_revenue
FROM FOOD_ORDERS;

-- Average order value (AOV)
SELECT AVG(ORDER_AMOUNT) AS avg_order_value
FROM FOOD_ORDERS;


-- Average delivery time
SELECT AVG(DELIVERY_TIME_MINUTES) AS avg_delivery_time
FROM FOOD_ORDERS;


-- INTERMEDIATE LEVEL – JOIN + AGGREGATION
-- Revenue generated by each restaurant
SELECT R.RESTAURANT_NAME,
       SUM(O.ORDER_AMOUNT) AS total_revenue
FROM FOOD_ORDERS O
JOIN FOOD_RESTAURANT R
  ON O.RESTAURANT_ID = R.RESTAURANT_ID
GROUP BY R.RESTAURANT_NAME
ORDER BY total_revenue DESC;

-- Number of orders per customer
SELECT C.CUSTOMER_NAME,
       COUNT(O.ORDER_ID) AS total_orders
FROM FOOD_CUSTOMERS C
JOIN FOOD_ORDERS O
  ON C.CUSTOMER_ID = O.CUSTOMER_ID
GROUP BY C.CUSTOMER_NAME
ORDER BY total_orders DESC;


-- City-wise number of orders
SELECT C.CITY,
       COUNT(O.ORDER_ID) AS total_orders
FROM FOOD_ORDERS O
JOIN FOOD_CUSTOMERS C
  ON O.CUSTOMER_ID = C.CUSTOMER_ID
GROUP BY C.CITY;




-- ADVANCED / ANALYTICAL BUSINESS QUESTIONS
--  Top 5 restaurants by revenue
SELECT R.RESTAURANT_NAME,
       SUM(O.ORDER_AMOUNT) AS revenue
FROM FOOD_ORDERS O
JOIN FOOD_RESTAURANT R
  ON O.RESTAURANT_ID = R.RESTAURANT_ID
GROUP BY R.RESTAURANT_NAME
ORDER BY revenue DESC
LIMIT 5;

--  Top 5 customers by spending
SELECT C.CUSTOMER_NAME,
       SUM(O.ORDER_AMOUNT) AS total_spent
FROM FOOD_CUSTOMERS C
JOIN FOOD_ORDERS O
  ON C.CUSTOMER_ID = O.CUSTOMER_ID
GROUP BY C.CUSTOMER_NAME
ORDER BY total_spent DESC
LIMIT 5;


--  Fastest delivery partners (lowest avg delivery time)
SELECT P.PARTNER_NAME,
       AVG(O.DELIVERY_TIME_MINUTES) AS avg_delivery_time
FROM FOOD_DELIVERY_PARTNERS P
JOIN FOOD_ORDERS O
  ON P.PARTNER_ID = O.PARTNER_ID
GROUP BY P.PARTNER_NAME
ORDER BY avg_delivery_time ASC
LIMIT 5;

-- Monthly revenue trend
SELECT 
    EXTRACT(MONTH FROM ORDER_DATE) AS month,
    SUM(ORDER_AMOUNT) AS monthly_revenue
FROM FOOD_ORDERS
GROUP BY month
ORDER BY month;



--  Customer retention (repeat customers)
SELECT CUSTOMER_ID,
       COUNT(ORDER_ID) AS order_count
FROM FOOD_ORDERS
GROUP BY CUSTOMER_ID
HAVING COUNT(ORDER_ID) > 1;























